import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface TripData {
  destination: string;
  budget: number;
  spent: number;
  remaining: number;
}

interface CategoryBreakdown {
  category: string;
  budget: number;
  spent: number;
}

interface WidgetData {
  trip: TripData;
  categoryBreakdown: CategoryBreakdown[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { trip, categoryBreakdown } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF6F61' }}>
              {trip.destination}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${trip.spent.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: '#64748B', mt: 0.5 }}>
              Spent of ${trip.budget.toLocaleString()} budget
            </Typography>
          </Box>

          <PieChart
            height={200}
            series={[
              {
                data: [
                  { value: trip.spent, name: 'Spent' },
                  { value: trip.remaining, name: 'Remaining' },
                ],
                colors: ['#FF6F61', '#FFD700'],
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiChartLabel-root': {
                fontSize: 11,
                fill: '#6B7280',
              },
            }}
          />

          <Grid container spacing={1}>
            {categoryBreakdown.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Chip
                  label={`${category.category}: $${category.spent.toLocaleString()}`}
                  sx={{ width: '100%', fontSize: '10px' }}
                />
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
